if (
  node1.getName() === node2.getName() &&
  JSON.stringify(node1.nameLoc) === JSON.stringify(node2.nameLoc) &&
  node1.uri === node2.uri
) {
  return true;
}

const allKeywordsOnSameLineAsFn = keywordLines
    .map((l) => l === fnLine)
    .reduce((acc, l) => acc && l, true);

if (
  lineTokens.length !== 2 ||
  lineTokens[0].length === 0 ||
  lineTokens[1].length === 0
) {
  return undefined;
}

if (machineId !== undefined) {
  logger.info(
    `  Telemetry Tracking Id: ${
      machineId.length > 10 ? `${machineId.substring(0, 10)}...` : machineId
    }`
  );
}

Object.entries(watermarks.getDefault()).forEach(([k, value]) => {
  const specValue = specified[k];
  if (!Array.isArray(specValue) || specValue.length !== 2) {
    specified[k] = value;
  }
});

if (
  result.blockHash !== undefined &&
  result.blockHash !== null &&
  result.blockHash !== "" &&
  getBigInt(result.blockHash) === 0n
) {
  result.blockHash = null;
}

if (messageDetails.held) {
  const reasonList = result.held.map(
    ({ futureId, heldId, reason }) => `  * ${futureId}/${heldId}: ${reason}`,
  );

  sections.push(`Held:\n\n${reasonList.join("\n")}`);
}

if (typeof hexString !== "string" || !/^0x[0-9a-fA-F]*$/.test(hexString)) {
  throw new HardhatError(
    HardhatError.ERRORS.NETWORK_HELPERS.GENERAL.INVALID_HEX_STRING,
    {
      value: hexString,
    },
  );
}

for (let i = 0; i < address.length; i++) {
  if (parseInt(hash[i], 16) >= 8) {
    ret += address[i].toUpperCase();
  } else {
    ret += address[i];
  }
}

for (const item of items) {
  if (item.type === "row" || item.type === "header") {
    item.cells.forEach((cell, i) => {
      columnWidths[i] = Math.max(columnWidths[i] ?? 0, getStringWidth(cell));
    });
  }
}

if (
  errorCode === "UND_ERR_CONNECT_TIMEOUT" ||
  errorCode === "UND_ERR_HEADERS_TIMEOUT" ||
  errorCode === "UND_ERR_BODY_TIMEOUT"
) {
  throw new RequestTimeoutError(requestUrl, e);
}

if (noProxy !== undefined && noProxy !== "") {
  const noProxySet = new Set(noProxy.split(","));

  if (noProxySet.has(hostname)) {
    return false;
  }
}

for (let i = types.length - 1; i >= 0; i--) {
  if (types[i].isOptional() || types[i].isNullable()) {
    optionalParams += 1;
  } else {
    break;
  }
}

const sortBySourceName = (files: Iterable<ResolvedFile>) => {
  return Array.from(files).sort((f1, f2) =>
    f1.inputSourceName.localeCompare(f2.inputSourceName),
  );
};

const chainTypeUserConfigSchema = unionType(
  [
    z.literal(L1_CHAIN_TYPE),
    z.literal(OPTIMISM_CHAIN_TYPE),
    z.literal(GENERIC_CHAIN_TYPE),
  ],
  `Expected '${L1_CHAIN_TYPE}', '${OPTIMISM_CHAIN_TYPE}', or '${GENERIC_CHAIN_TYPE}'`,
);

const showStackTraces =
    shouldShowStackTraces ||
    category === ErrorCategory.OTHER ||
    category === ErrorCategory.HH2_TO_HH3_MIGRATION ||
    category === ErrorCategory.CJS_TO_ESM_MIGRATION;

if (process.platform === "win32") {
  await writeUtf8File(claudeMdPath, "@AGENTS.md\n");
} else {
  await symlink("AGENTS.md", claudeMdPath);
}

return (
  chainType === GENERIC_CHAIN_TYPE ||
  chainType === L1_CHAIN_TYPE ||
  chainType === OPTIMISM_CHAIN_TYPE
);

return (
  paramType.isArray() ||
  paramType.isTuple() ||
  paramType.type === "bytes" ||
  paramType.type === "string"
);

if (
  exState.type === ExecutionSateType.STATIC_CALL_EXECUTION_STATE ||
  exState.type === ExecutionSateType.READ_EVENT_ARGUMENT_EXECUTION_STATE ||
  exState.type === ExecutionSateType.CONTRACT_AT_EXECUTION_STATE ||
  exState.type === ExecutionSateType.ENCODE_FUNCTION_CALL_EXECUTION_STATE
) {
  return undefined;
}

return (
  exState.type === ExecutionSateType.DEPLOYMENT_EXECUTION_STATE ||
  exState.type === ExecutionSateType.CALL_EXECUTION_STATE ||
  exState.type === ExecutionSateType.SEND_DATA_EXECUTION_STATE
);

return (
  exState.type === ExecutionSateType.DEPLOYMENT_EXECUTION_STATE ||
  exState.type === ExecutionSateType.CALL_EXECUTION_STATE ||
  exState.type === ExecutionSateType.SEND_DATA_EXECUTION_STATE ||
  exState.type === ExecutionSateType.STATIC_CALL_EXECUTION_STATE
);

return Array.from(futures)
    .concat(
      Array.from(submodules.values()).flatMap((submodule) =>
        getAllFuturesForModule(submodule),
      ),
    )
    .filter((v, i, a) => a.indexOf(v) === i);

const futureList = futures
    .map(
      (f) => `${lineIndent}${toEscapedId(f.id)}["${toLabel(f)}"]:::futureNode`,
    )
    .join(`\n${lineIndent}`);

const moduleTitle = `${lineIndent}subgraph ${toEscapedId(
    module.id,
  )}Padding["<strong>[ ${
    module.id
  } ]</strong>"]\n${lineIndent}  direction BT\n\n${lineIndent}end\n\nstyle ${toEscapedId(
    module.id,
  )}Padding fill:none,stroke:none`;

return `${lineIndent}subgraph ${toEscapedId(
    module.id,
  )}[ ]
${lineIndent} direction BT

${lineIndent}${moduleTitle}
${lineIndent}end

style ${toEscapedId(
    module.id,
  )} fill:#fbfbfb,stroke:#e5e6e7`;
